import{getDayEnd,getDayStart,getDecadeEnd,getDecadeStart,getMonthEnd,getMonthStart,getYearEnd,getYearStart}from"@wojtekmaj/date-utils";function getBegin(e,t){switch(e){case"decade":return getDecadeStart(t);case"year":return getYearStart(t);case"month":return getMonthStart(t);case"day":return getDayStart(t);default:throw new Error("Invalid rangeType: "+e)}}function getEnd(e,t){switch(e){case"decade":return getDecadeEnd(t);case"year":return getYearEnd(t);case"month":return getMonthEnd(t);case"day":return getDayEnd(t);default:throw new Error("Invalid rangeType: "+e)}}export{getBegin,getEnd};